class Mandelbrot extends Fractal {
	MAX_ITERATION = 20
	real0 = new Complex(-2, 2); 
	imaginary0 = new Complex(-2, 2);
	
	constructor(config) {
		super(config);
	}
	
	init() {
		super.init();
		this.config.canvas.addEventListener('click', (e) => {this.onDblClick(e);});
	}
	
	onDblClick(e) {
	    var canvas = this.config.canvas;
	    var x = e.pageX - canvas.offsetLeft;
	    var y = e.pageY - canvas.offsetTop;
	    
	    this.doZoom(x, y, 1);
	    this.draw();
	}
	
	doZoom(x, y, sign) {
	    var width = this.config.width;
		var height = this.config.height;
	    var zfw = (width * this.config.zoomStep) * sign;
	    var zfh = (height * this.config.zoomStep) * sign;
		log(x + ' ' + y + ' ' + zfw + ' ' + zfh)
		this.real0 =  new Complex(
	        this.getRelativePoint(x - zfw, width, this.real0),
	        this.getRelativePoint(x + zfw, width, this.real0) );
	    this.imaginary0 =  new Complex(
	        this.getRelativePoint(y - zfh, height, this.imaginary0),
	        this.getRelativePoint(y + zfh, height, this.imaginary0) );
	    
	}
	
	getRelativePoint(pixel, length, set) {
	   return set.x + (pixel / length) * (set.y - set.x);
	}
	
	setGraphColor() {
		this.draw();
	}
	
	setBgColor(rgb) {
		this.draw();
	}
	
	redraw() {
		this.draw();	
	}
	
	getControlUI() {
		var t = '<table>';
		t += '<tr>';
		t += '<td>Zoom: <button onclick="Index.zoomIn();" type="button" class="btn btn-outline-info">+</button></td>';
		t += '<td><button onclick="Index.zoomOut();" type="button" class="btn btn-outline-info">-</button></td>';
		t += '<td><button onclick="Index.setRandomColor();" type="button" class="btn btn-outline-info">Random Color</button></td>';
		t += '</tr>';			
		
		t += '</table>';
		return t;
	}
	
	zoomIn() {
		this.zoom += this.config.zoomStep;
	    var x = this.config.width/2;
	    var y = this.config.height/2;
	    
	    this.doZoom(x, y, 1);
		this.draw();
	}
	zoomOut() {
		this.zoom -= this.config.zoomStep;
	    var x = this.config.width/2;
	    var y = this.config.height/2;	    
	    this.doZoom(x, y, -1);
		this.draw();
	}
	setRandomColor() {
		this.config.isRandomColor = !this.config.isRandomColor;
		this.draw();
	}
	
	draw() {
		this.clear();
		this.plot();
	}	
	
	mandelbrot(c) {
	    var z = new Complex(0, 0);
	    var n = 0;
	    var p, d;
	    do {
	    	p = new Complex(Math.pow(z.x, 2) - Math.pow(z.y, 2), 2 * z.x * z.y);
	        z = new Complex(p.x + c.x, p.y + c.y);
	        d = Math.sqrt(Math.pow(z.x, 2) + Math.pow(z.y, 2));
	        n += 1
	    } while (d <= 2 && n < this.MAX_ITERATION)
	    return [n, d <= 2];
	}	

	plot() {
		var colors;
		if ( this.config.isRandomColor ) {
			colors = FractalFactory.getColorPallet().randomColors;
		} else {
			colors = FractalFactory.getColorPallet().rainbowColors;			
		}
		
		var width = this.config.width;
		var height = this.config.height;
		var real0 = this.real0;
		var imaginary0 = this.imaginary0;	
	    for (let i = 0; i < width; i++) {
	        for (let j = 0; j < height; j++) {
	            var complex = new Complex(
	            	real0.x + (i/width) * (real0.y - real0.x),
	                imaginary0.x + (j/height) * (imaginary0.y - imaginary0.x)
	            );

	            var [m, isMandelbrotSet] = this.mandelbrot(complex)
	            if ( this.config.isColor ) {
		            if ( isMandelbrotSet ) {
		            	var c = this.config.foregroundConfig.getColor(i, j);
		            	this.fillOnePixelByColor(i, j, c)
		            } else {
		            	var c = colors[m % (colors.length - 1)];
		            	this.fillOnePixelByColor(i, j, c);
		            }
	            } else {
	            	var c;
	            	if ( isMandelbrotSet ) {
	            		c = this.config.foregroundConfig.getColor();
	            	} else {
	            		c = this.config.backgroundConfig.getColor();
	            	}
	            	this.fillOnePixelByColor(i, j, c);
	            }
	        }
	    }
	}	
}

class Complex {
	x=0;
	y=0;
	constructor(x, y) {
		this.x = x;
		this.y = y;
	}
}
class IFS {
	name;
	maps;
	x1; y1; x2; y2;

	_originalMap;
	_originalProbs;
	constructor(name, maps) {
		this.name = name;
		this.maps = maps;
	}
			
	getWhichMap() {
		var r = Math.random();
		for (var k=0; k<this.maps.length; k++) {
			r -= this.maps[k][6];
			if ( r < 0 ) {
				return k;
			}
		}
		return 0;
	}
	
	toString() {
		return this.name;
	}
	
	getColor(index) {
		return this.rgb_colors[index%this.rgb_colors.length]
	}
	
	backupMaps() {
		this._originalMap = JSON.parse(JSON.stringify(this.maps));
	}
	
	toUI() {
		var t = '<table>';
		for (var i=0; i<this.maps.length; i++) {
			var m = this.maps[i];
			t += '<tr>';
			
			t += '<td>';
			t += '<label class="checkbox-inline">';
			t += '<input type="checkbox" value="' + i + '" checked="checked" name="ifcMap" onclick="Index.selectMap()"></label>';
			t += '</td>';
			
			for (var j=0; j<m.length; j++) {
				t += '<td>';
				t += '<input type="text" onfocus="Index.setFocused(this);" value="' + m[j] 
					+ '" size="2" class="form-control mb-2 mr-sm-2" id="'
					+ this.getDataId(i, j) + '">';
				t += '</td>';						
			}		
			t += '<td><button onclick="IFS.deleteRow(' + i + ');" type="button" class="btn btn-outline-info">Delete</button></td>';
			t += '</tr>';		
			
			
		}
		t += '<tr>';
		t += '<td><button onclick="IFS.addRow();" type="button" class="btn btn-outline-info">Add</button></td>';
		t += '<td><button onclick="IFS.clear();" type="button" class="btn btn-outline-info">Clear</button></td>';		
		t += '<td><button onclick="Index.reset();" type="button" class="btn btn-outline-info">Reset</button></td>';		
		t += '<td><button onclick="Index.redraw();" type="button" class="btn btn-outline-info">Redraw</button></td>';		
		t += '</tr>';		
		
		t += '</table>';
		
		return t;
	}
	
	static deleteRow(index) {
		var fractal = Index.getCurrentFractal();
		var ifs = fractal.ifs;
		ifs.maps = Util.deleteElement(ifs.maps, index);
		fractal.showControlUI();
		fractal.redraw();
	}
	
	static addRow() {
	}
	static clear() {
	}
	
	getDataId(i, j) {
		return 'data_' + i + '_' + j;
	}
	updateMap() {
		for (var i=0; i<this.maps.length; i++) {
			var m = this.maps[i];
			for (var j=0; j<m.length; j++) {
				m[j] = Util.getFloat(this.getDataId(i, j));
			}
		}
	}
	
	printMap() {
		for (var i=0; i<this.maps.length; i++) {
			var m = this.maps[i];
			var t = '';
			for (var j=0; j<m.length; j++) {
				t += ' ' + m[j]
			}
			log(t)
		}		
	}
}

class RGB {
	r=0; g=0; b=0; a=1.0;
	constructor(r, g, b, a) {
		this.r = r;
		this.g = g;
		this.b = b;
		if ( a != null ) {
			this.a = a;
		}
	}
	
	toString() {
		return 'rgb(' + this.r + ',' + this.g + ',' + this.b + ',' + this.a + ')';
	}
}
